search:Node.js + MongoDB Advanced Indexi.content:
- **CLI Commands**:
  - `mongo --eval "db.collection.createIndex({field: 1})"` to create a single field index.
  - `mongo --eval "db.collection.createIndex([ { field1: 1 }, { field2: -1 } ])"` for compound indexes.

- **Latest Versions**:
  - MongoDB Node.js Driver: v7.0.0
  - MongoDB Server: v6.0.0

- **Key Config Options**:
  - `background`: Set to true to create index in the background.
  - `unique`: Enforce uniqueness on indexed field(s).
  - `expireAfterSeconds`: Define TTL for documents.

- **Example Code Snippets**:
  ```javascript
  const MongoClient = require('mongodb').MongoClient;

  async function run() {
    const uri = "your_mongodb_connection_string";
    const client = new MongoClient(uri);

    try {
      await client.connect();
      const database = client.db('testdb');
      const collection = database.collection('users');

      // Create a single field index
      await collection.createIndex({ email: 1 }, { unique: true });

      // Create a compound index
      await collection.createIndex([ { age: 1 }, { name: -1 } ], { background: true });
    } finally {
      await client.close();
    }
  }

  run().catch(console.dir);
  ```
